export interface Particle {
    x: number;
    y: number;
    vx: number;
    vy: number;
    life: number;
    maxLife: number;
    size: number;
    color: string;
    alpha: number;
    active: boolean;
}

export interface ParticleEmitterConfig {
    x: number;
    y: number;
    count: number;
    spread: number;
    speed: number;
    life: number;
    size: number;
    color: string;
    gravity?: number;
}

export class ParticleSystem {
    private engine: unknown;
    private particles: Particle[] = [];
    private maxParticles: number = 1000;
    private initialized: boolean = false;

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async initialize(): Promise<void> {
        console.log('✨ ParticleSystem 初始化...');
        this.initialized = true;
        console.log('✅ ParticleSystem 初始化完成');
    }

    emit(config: ParticleEmitterConfig): void {
        const count = Math.min(config.count, this.maxParticles - this.particles.length);

        for (let i = 0; i < count; i++) {
            const angle = Math.random() * Math.PI * 2;
            const speed = config.speed * (0.5 + Math.random() * 0.5);

            const particle: Particle = {
                x: config.x + (Math.random() - 0.5) * config.spread,
                y: config.y + (Math.random() - 0.5) * config.spread,
                vx: Math.cos(angle) * speed,
                vy: Math.sin(angle) * speed,
                life: config.life * (0.5 + Math.random() * 0.5),
                maxLife: config.life,
                size: config.size * (0.5 + Math.random() * 0.5),
                color: config.color,
                alpha: 1,
                active: true
            };

            this.particles.push(particle);
        }
    }

    update(deltaTime: number): void {
        const dt = deltaTime / 1000;

        for (let i = this.particles.length - 1; i >= 0; i--) {
            const p = this.particles[i];

            if (!p.active) {
                this.particles.splice(i, 1);
                continue;
            }

            p.x += p.vx * dt * 60;
            p.y += p.vy * dt * 60;
            p.vy += 0.1 * dt * 60;
            p.life -= dt;

            if (p.life <= 0) {
                p.active = false;
                continue;
            }

            p.alpha = p.life / p.maxLife;
        }
    }

    render(ctx: CanvasRenderingContext2D): void {
        for (const p of this.particles) {
            if (!p.active) continue;

            ctx.globalAlpha = p.alpha;
            ctx.fillStyle = p.color;
            ctx.beginPath();
            ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
            ctx.fill();
        }

        ctx.globalAlpha = 1;
    }

    getParticleCount(): number {
        return this.particles.length;
    }

    clear(): void {
        this.particles = [];
    }

    destroy(): void {
        this.particles = [];
        this.initialized = false;
    }
}

export default ParticleSystem;
